    "cases.defects_liability_period_tracking.step.log.out.entry": "Geregistreerd gebrek",
    "cases.defects_liability_period_tracking.step.log.title": "Registreer het gemelde gebrek",
    "cases.defects_liability_period_tracking.step.log.what": "Voeg het door de gebruiker gemelde gebrek toe aan de opleverlijst met locatie, foto en de aannemer of onderaannemer die verantwoordelijk is voor het herstel.",
    "cases.defects_liability_period_tracking.step.log.why": "Een gebrek dat telefonisch aan een huismeester wordt gemeld en nooit wordt vastgelegd, wordt nooit verholpen. Eén lijst houdt elke claim tegen de garantietermijn zichtbaar.",
    "cases.defects_liability_period_tracking.title": "Beheer de garantietermijn na ingebruikname",
    "cases.design_query_from_bim_coordination.desc": "Maak van een conflict dat in het gefedereerde model is ontdekt een formele ontwerpvraag, laat deze door de juiste discipline beantwoorden en werk het model bij zodra de oplossing is doorgevoerd.",
    "cases.design_query_from_bim_coordination.step.query.in.conflict": "Gelokaliseerd conflict",
