    "cases.design_query_from_bim_coordination.step.query.out.tracked": "Getraceerde RFI",
    "cases.design_query_from_bim_coordination.step.query.title": "Stel de vraag",
    "cases.design_query_from_bim_coordination.step.query.what": "Dien een formeel verzoek in met vermelding van het element, de modelweergave waarin het is gevonden en de clash of het conflict dat het veroorzaakt, met een datum gekoppeld aan wanneer het vak het antwoord nodig heeft.",
    "cases.design_query_from_bim_coordination.step.query.why": "Een conflict dat in een vergadering wordt genoemd maar nooit wordt geformaliseerd, is tegen de volgende vergadering vergeten. Een gedateerde, schriftelijke vraag houdt het in beweging totdat het daadwerkelijk is opgelost.",
    "cases.design_query_from_bim_coordination.step.review.in.federation": "Gefedereerd model",
