    "cases.design_query_from_bim_coordination.step.review.out.discipline": "Verantwoordelijke discipline",
    "cases.design_query_from_bim_coordination.step.review.title": "Beoordeel het gefedereerde model",
    "cases.design_query_from_bim_coordination.step.review.what": "Open de federatie en bekijk het gebied dat tijdens de coördinatievergadering is gemarkeerd, en controleer welke disciplinemodel daadwerkelijk moet worden aangepast.",
    "cases.design_query_from_bim_coordination.step.review.why": "Een vraag die bij de verkeerde discipline wordt ingediend, komt een week later gewoon terug. De bron eerst bevestigen in het gefedereerde model zorgt dat het meteen bij het juiste bureau terechtkomt.",
    "cases.design_query_from_bim_coordination.step.update.in.answer": "Antwoord op de vraag",
