    "cases.maintain_supplier_catalogs_and_buy_from_them.step.buy.out.schedule": "Beprijsd inkoopschema",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.buy.title": "Stel het inkoopschema op",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.buy.what": "Bouw het inkoopschema van het project op en beprijs elk pakket rechtstreeks vanuit de actuele leverancierscatalogi, zodat elke regel een echt geoffreerd tarief draagt in plaats van een geraden budgetpost.",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.buy.why": "De inkoop beprijzen tegen de actuele catalogus maakt van een ruwe budgetpost een vastgelegd bedrag waar je de leverancier aan kunt houden, en het markeert elk item waarvan de markt is verschoven sinds de raming.",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.catalogs.in.pricelists": "Prijslijsten van leveranciers",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.catalogs.in.updates": "Nieuwe prijsupdates",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.catalogs.out.catalog": "Actuele leverancierscatalogi",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.catalogs.out.rates": "Actuele inkooptarieven",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.catalogs.title": "Importeer en actualiseer leverancierscatalogi",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.catalogs.what": "Importeer elke leverancierprijslijst in een eigen catalogus en werk deze bij zodra nieuwe prijzen binnenkomen, zodat de tarieven waartegen je inkoopt de tarieven zijn die de leverancier vandaag hanteert.",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.catalogs.why": "Inkopen tegen een verouderde prijslijst is hoe een pakket over budget belandt nog voordat er één bestelling de deur uit is. Een actuele catalogus houdt de raming en de bestelling op dezelfde cijfers.",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.report.in.allowance": "Budgetposten uit de raming",
