    "cases.run_the_submittals_register.step.attach-spec.out.clause": "Gekoppelde bestekclausule",
    "cases.run_the_submittals_register.step.attach-spec.title": "Koppel het bestek",
    "cases.run_the_submittals_register.step.attach-spec.what": "Koppel vanuit QMS de bestekclausule waaraan de indiening wordt getoetst.",
    "cases.run_the_submittals_register.step.attach-spec.why": "Een beoordelaar heeft het bestek naast de indiening nodig, anders is de goedkeuring slechts een mening. Het beslecht ook latere discussies over wat er daadwerkelijk was voorgeschreven.",
    "cases.run_the_submittals_register.step.issue-review.in.package": "Indieningspakket",
    "cases.run_the_submittals_register.step.issue-review.in.reviewer": "Ontwerpbeoordelaar",
    "cases.run_the_submittals_register.step.issue-review.out.comments": "Beoordelingsopmerkingen",
    "cases.run_the_submittals_register.step.issue-review.out.status": "Beoordelingsstatus",
    "cases.run_the_submittals_register.step.issue-review.title": "Geef vrij voor beoordeling",
    "cases.run_the_submittals_register.step.issue-review.what": "Geef in Correspondentie de indiening vrij voor beoordeling en registreer de status die terugkomt: goedgekeurd, goedgekeurd met opmerkingen of afgekeurd.",
    "cases.run_the_submittals_register.step.issue-review.why": "De teruggekomen status is de trigger om te bestellen of opnieuw in te dienen, dus moet die bij het item worden vastgelegd. Een mondeling akkoord geeft de inkoop niet vrij.",
    "cases.run_the_submittals_register.step.log.in.drawings": "Werktekeningen",
    "cases.run_the_submittals_register.step.log.in.submittals": "Technische indieningen",
    "cases.run_the_submittals_register.step.log.out.dates": "Vereiste einddata",
    "cases.run_the_submittals_register.step.log.out.register": "Indieningenregister",
    "cases.run_the_submittals_register.step.log.title": "Registreer de indieningen",
    "cases.run_the_submittals_register.step.log.what": "Registreer in Indieningen elke werktekening en technische indiening en stel de datum in waarop goedkeuring nodig is.",
    "cases.run_the_submittals_register.step.log.why": "Een te laat goedgekeurde indiening houdt de bestelling op, en een te late bestelling houdt het vak op de bouwplaats op. Het register is waar je dit ziet aankomen.",
    "cases.run_the_submittals_register.step.report.in.log": "Indieningenlogboek",
