    "cases.run_the_submittals_register.step.report.title": "Rapporteer wat achterstallig is",
    "cases.run_the_submittals_register.step.report.what": "Publiceer in Rapporten het indieningenlogboek en licht eruit wat achterstallig is en de inkoop blokkeert.",
    "cases.run_the_submittals_register.step.report.why": "De mensen die materiaal bestellen hebben één duidelijke lijst nodig van wat vastzit en waarom. Achterstallige indieningen zijn de stille reden dat een planning uitloopt.",
    "cases.run_the_submittals_register.title": "Beheer het indieningenregister",
    "cases.schedule_and_track.desc": "Plan de planning, bevries een basisplanning om tegen te meten, voed werkelijke voortgang vanaf de bouwplaats terug en lees de afwijking af zodat vertraging vroeg zichtbaar wordt.",
    "cases.schedule_and_track.step.actuals.in.activities": "Planningsactiviteiten",
