    "cases.set_up_the_asset_register_for_fm.step.locate.in.specs": "Apparatuurspecificaties",
    "cases.set_up_the_asset_register_for_fm.step.locate.out.data": "Kerngegevens activum",
    "cases.set_up_the_asset_register_for_fm.step.locate.out.located": "Gelokaliseerde activa",
