    "cases.turn_field_time_into_payroll_and_labour_cost.desc": "Neem de goedgekeurde uren van de bouwplaats, verwerk ze in de loonadministratie tegen de juiste schaal en tarief, en boek de loonkosten op het project, zodat het kostenrapport laat zien wat het werk daadwerkelijk heeft gekost.",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.collect.in.approval": "Goedkeuring uitvoerder",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.collect.in.timesheets": "Urenstaten uit het veld",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.collect.out.codes": "Uren per kostencode",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.collect.out.hours": "Goedgekeurde uren",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.collect.title": "Verzamel de goedgekeurde urenstaten",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.collect.what": "Haal de week aan urenstaten op van het veld, gecontroleerd en goedgekeurd door de uitvoerder, met uren geboekt per medewerker en op de juiste kostencode.",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.collect.why": "Een loonrun op basis van niet-goedgekeurde uren betaalt tijd waarvoor niemand heeft getekend. Goedgekeurde urenstaten zijn de ene schone bron waarop zowel het loon als de projectkosten zijn gebouwd.",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.post.in.codes": "Kostencodes",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.post.in.total": "Loontotaal",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.post.out.costtodate": "Bijgewerkte kosten tot nu toe",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.post.out.posted": "Loonkosten geboekt",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.post.title": "Boek loonkosten op het project",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.post.what": "Boek het loontotaal op het projectgrootboek tegen de juiste kostencodes, zodat de loonuitgaven naast materiaal, materieel en onderaanneming staan.",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.post.why": "Een kostenrapport zonder loonkosten vertelt je dat het project goedkoper is dan het is. Het boeken van de loonsom op het project maakt de kosten tot nu toe compleet en de marge eerlijk.",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.run.in.hours": "Goedgekeurde uren",
    "cases.turn_field_time_into_payroll_and_labour_cost.step.run.in.rates": "Schaal- en tarieventabel",
