    "howto.cat.controls": "Beheersing & BI",
    "howto.cat.controls.desc": "Projectbeheersing, dashboards en basislijnmomentopnamen.",
    "howto.cat.coordination": "Modelcoordinatie",
    "howto.cat.coordination.desc": "Federeer modellen, vind clashes en toets ze aan eisen.",
    "howto.cat.cost_control": "Kostenbeheersing & risico",
    "howto.cat.cost_control.desc": "Volg het budget tegen werkelijke kosten, nivelleer middelen en kwantificeer risico.",
    "howto.cat.cost_data": "Kostengegevens",
    "howto.cat.cost_data.desc": "De catalogi, samenstellingen en benchmarks waaruit uw prijzen komen.",
    "howto.cat.documents": "Documenten",
