    "reporting.no_projects_desc": "Maak een project aan om hier de KPI's te volgen.",
    "reporting.create_project": "Project aanmaken",
    "reporting.choose_project": "Kies een project",
    "reporting.open_pm_for": "Projectmanager-dashboard openen voor het geselecteerde project",
    "reporting.stats_load_failed": "Kon de metrieken van dit project niet laden. Controleer uw verbinding en probeer het opnieuw.",
